import { sneakersList } from '../datas/sneakersList';
import SneakerItem from './SneakerItem';

function ShoppingList() {
    return (
        <div className="shopping-list">
            <h2>Nos Sneakers</h2>
            <div className="sneakers-grid">
                {/* Test avec seulement la première sneaker */}
                <SneakerItem 
                    key={sneakersList[0].id}
                    nom={sneakersList[0].nom}
                    marque={sneakersList[0].marque}
                    prix={sneakersList[0].prix}
                    style={sneakersList[0].style}
                />
            </div>
        </div>
    );
}

export default ShoppingList;
